-- Install the creation-only Crafter's Ledger catalogue.
-- Safe to run more than once. Character crafting progress remains in the existing state JSON.

begin;

alter table public.catalogue_entries
  drop constraint if exists catalogue_entries_category_check;

alter table public.catalogue_entries
  add constraint catalogue_entries_category_check
  check (
    category in (
      'traits',
      'conditions',
      'items',
      'food_dishes',
      'food_ingredients',
      'food_rules',
      'crafting_sections',
      'crafting_materials',
      'crafting_recipes'
    )
  );

insert into public.catalogue_entries (category, stable_key, sort_order, data)
select
  'crafting_materials',
  'crafting_materials:' || lower(entry.item ->> 'id'),
  entry.ordinality - 1,
  entry.item
